#include <iostream>#include <vector>#include <algorithm>#include <cmath>#include <string>#include <map>#include <set>#include <iomanip>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n;    cin >> n;        vll a(n);    for(int i=0; i<n; i++) cin >> a[i];    if(a[0]==1){        a[0]+=1;    }    for(int i=1;i<n;i++){        if(a[i]==1){            a[i]+=1;        }        if(a[i]%a[i-1]==0){            a[i]+=1;        }    }     for(int i=0;i<n;i++){        cout << a[i] << " ";    }    cout << "\n";} // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}